1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Step {
8	  type: string;
9	  items: Item[];
10	}
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	  quoteNumber?: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: Step[];
20	}
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	
25	const BASE_PREMIUM: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	const BLOCK_SIZE = 3;
36	const BLOCK_PREMIUM = 60;
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
40	const LOYALTY_THRESHOLD_YEARS = 2;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
43	
44	function calculateBasePremium(items: Item[]): number {
45	  const typeCounts: Record<string, number> = {};
46	  for (const item of items) {
47	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
48	  }
49	
50	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
51	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
52	      ? BLOCK_PREMIUM
53	      : count * BASE_PREMIUM[type];
54	    return total + premium;
55	  }, 0);
56	}
57	
58	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
59	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
60	    ? basePremium * LOYALTY_DISCOUNT_RATE
61	    : 0;
62	}
63	
64	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
65	  return (customer.quoteNumber ?? 1) >= 2
66	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
67	    : 0;
68	}
69	
70	function calculateItemSurcharges(items: Item[]): number {
71	  return items.reduce((total, item) => {
72	    const itemBasePremium = BASE_PREMIUM[item.type];
73	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
74	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
75	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
76	      : 0;
77	    return total + curseSurcharge + enchantmentSurcharge;
78	  }, 0);
79	}
80	
81	export function processScenario(scenario: Scenario): unknown {
82	  const items = scenario.steps[0].items;
83	  const basePremium = calculateBasePremium(items);
84	  const itemSurcharges = calculateItemSurcharges(items);
85	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
86	  const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
87	  const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
88	  const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
89	
90	  return [{ premium }];
91	}
